('computer-science:1-5-2-utility-software:match:3bba8784', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Utility software”?", "options": ["A security utility that monitors and filters network traffic against rules", "A security utility that scans for and removes malicious software", "Copies every file and all data every time it runs", "System software that helps to maintain, configure and optimise the computer"]}'::jsonb, '{"answer": 3, "explain": "“Utility software” means: System software that helps to maintain, configure and optimise the computer"}'::jsonb),
('computer-science:1-5-2-utility-software:match:69f3ef82', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fragmentation”?", "options": ["When a file''s data becomes split into pieces stored in scattered places across a disk", "Scrambles data using a key so it cannot be understood without that key", "Makes a spare copy of data, stored separately, so it can be restored if lost", "A security utility that monitors and filters network traffic against rules"]}'::jsonb, '{"answer": 0, "explain": "“Fragmentation” means: When a file''s data becomes split into pieces stored in scattered places across a disk"}'::jsonb),
('computer-science:1-5-2-utility-software:match:8edcff95', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Defragmentation”?", "options": ["Reorganises the disk so each file''s pieces are stored together and free space is collated", "Tests the system to find faults and errors and report what is wrong", "When a file''s data becomes split into pieces stored in scattered places across a disk", "System software that helps to maintain, configure and optimise the computer"]}'::jsonb, '{"answer": 0, "explain": "“Defragmentation” means: Reorganises the disk so each file''s pieces are stored together and free space is collated"}'::jsonb),
('computer-science:1-5-2-utility-software:match:b9b8a949', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Data compression”?", "options": ["Reduces the size of a file so it uses less storage and is faster to transfer", "Tests the system to find faults and errors and report what is wrong", "Reorganises the disk so each file''s pieces are stored together and free space is collated", "Reports details about the computer, such as its processor, RAM and OS version"]}'::jsonb, '{"answer": 0, "explain": "“Data compression” means: Reduces the size of a file so it uses less storage and is faster to transfer"}'::jsonb),
('computer-science:1-5-2-utility-software:match:182cfd73', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Encryption software”?", "options": ["A security utility that monitors and filters network traffic against rules", "Makes a spare copy of data, stored separately, so it can be restored if lost", "Tests the system to find faults and errors and report what is wrong", "Scrambles data using a key so it cannot be understood without that key"]}'::jsonb, '{"answer": 3, "explain": "“Encryption software” means: Scrambles data using a key so it cannot be understood without that key"}'::jsonb),
('computer-science:1-5-2-utility-software:match:1beaad25', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Backup software”?", "options": ["Reduces the size of a file so it uses less storage and is faster to transfer", "Reorganises the disk so each file''s pieces are stored together and free space is collated", "Makes a spare copy of data, stored separately, so it can be restored if lost", "Copies only the files that have changed since the last backup"]}'::jsonb, '{"answer": 2, "explain": "“Backup software” means: Makes a spare copy of data, stored separately, so it can be restored if lost"}'::jsonb),
('computer-science:1-5-2-utility-software:match:6f11a775', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Full backup”?", "options": ["Makes a spare copy of data, stored separately, so it can be restored if lost", "Scrambles data using a key so it cannot be understood without that key", "Reports details about the computer, such as its processor, RAM and OS version", "Copies every file and all data every time it runs"]}'::jsonb, '{"answer": 3, "explain": "“Full backup” means: Copies every file and all data every time it runs"}'::jsonb),
('computer-science:1-5-2-utility-software:match:b98a9276', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Incremental backup”?", "options": ["Copies only the files that have changed since the last backup", "Reduces the size of a file so it uses less storage and is faster to transfer", "Reorganises the disk so each file''s pieces are stored together and free space is collated", "Reports details about the computer, such as its processor, RAM and OS version"]}'::jsonb, '{"answer": 0, "explain": "“Incremental backup” means: Copies only the files that have changed since the last backup"}'::jsonb),
('computer-science:1-5-2-utility-software:match:91bb9d02', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “System information utility”?", "options": ["System software that helps to maintain, configure and optimise the computer", "Reports details about the computer, such as its processor, RAM and OS version", "A security utility that monitors and filters network traffic against rules", "Copies every file and all data every time it runs"]}'::jsonb, '{"answer": 1, "explain": "“System information utility” means: Reports details about the computer, such as its processor, RAM and OS version"}'::jsonb),
('computer-science:1-5-2-utility-software:match:6514ee76', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Diagnosis utility”?", "options": ["Reduces the size of a file so it uses less storage and is faster to transfer", "System software that helps to maintain, configure and optimise the computer", "Tests the system to find faults and errors and report what is wrong", "A security utility that monitors and filters network traffic against rules"]}'::jsonb, '{"answer": 2, "explain": "“Diagnosis utility” means: Tests the system to find faults and errors and report what is wrong"}'::jsonb),
('computer-science:1-5-2-utility-software:match:ee187add', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Anti-malware”?", "options": ["Reports details about the computer, such as its processor, RAM and OS version", "When a file''s data becomes split into pieces stored in scattered places across a disk", "A security utility that scans for and removes malicious software", "Copies every file and all data every time it runs"]}'::jsonb, '{"answer": 2, "explain": "“Anti-malware” means: A security utility that scans for and removes malicious software"}'::jsonb),
('computer-science:1-5-2-utility-software:match:708920cf', 'computer-science', 'computer-science:1-5-2-utility-software', '1.5.2 Utility Software', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Firewall”?", "options": ["A security utility that monitors and filters network traffic against rules", "Reorganises the disk so each file''s pieces are stored together and free space is collated", "Reports details about the computer, such as its processor, RAM and OS version", "Copies every file and all data every time it runs"]}'::jsonb, '{"answer": 0, "explain": "“Firewall” means: A security utility that monitors and filters network traffic against rules"}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:1e5ccb5f', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "A company designs its phones so that the battery cannot be replaced and stops holding charge after two years. What kind of impact does this MOST raise?", "options": ["Only a purely technical impact, because it is simply a normal design choice about the battery inside the phone", "An ethical and environmental impact, because it pushes people to replace working phones, adding to e-waste", "No real impact at all, since customers can always just buy a completely different phone from another company", "Only a cultural impact, because it changes the specific way that people talk to each other using their phones"]}'::jsonb, '{"answer": 1, "explain": "Designing devices to fail sooner is an ethical concern (is it fair?) and an environmental one (more e-waste) — it pushes people to replace working phones."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:53731bd6', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Which of the following is the best example of a privacy impact of digital technology?", "options": ["A shopping website builds a detailed profile of a user by tracking everything they view, buy and search for", "A shopping website is temporarily unavailable because too many customers are trying to use it at once", "A shopping website loads its product pages more slowly on an older phone than it does on a brand new one", "A shopping website offers its products in several different languages so more customers around the world can use it"]}'::jsonb, '{"answer": 0, "explain": "Building a profile by tracking a user''s activity is a privacy impact. The others are about availability, performance and accessibility."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:92398e40', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Which is a positive cultural impact of digital technology?", "options": ["Electronic devices that are thrown away add to the growing global problem of dangerous electronic waste", "People can work together and stay in contact with others all over the world without having to travel", "Manufacturing new devices uses up scarce raw materials that have to be mined out of the ground first", "Companies can track exactly what their customers are doing online in order to sell them more products"]}'::jsonb, '{"answer": 1, "explain": "Being able to connect and collaborate worldwide is a positive cultural impact. The others are environmental or privacy concerns."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:ac90969a', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "A rural village finally gets a fast internet connection for the first time. Which stakeholder benefit is most directly a cultural one?", "options": ["The internet company that installed the connection is now able to make a larger profit from the village", "Villagers can now access online education, jobs and services that they were previously shut out from", "The copper and fibre cables that were laid down will slowly wear out and need replacing in the future", "The new equipment installed in the village will use some electrical energy while it is switched on and running"]}'::jsonb, '{"answer": 1, "explain": "Gaining access to online education, jobs and services changes how the community lives — a cultural impact (and it reduces the digital divide)."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:d54ed395', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Which of these actions would most help REDUCE the environmental impact of digital technology?", "options": ["Releasing a brand new model of a device every few months so that customers always have the very latest one", "Recycling old devices for their materials and donating working ones to people who need them", "Designing devices so that they cannot be repaired and have to be completely replaced when anything breaks", "Encouraging every customer to buy several backup devices in case their main device ever stops working one day"]}'::jsonb, '{"answer": 1, "explain": "Recycling and donating devices reduces e-waste and the need to manufacture new ones — reducing environmental impact."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:1c70eb5e', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "What does ''e-waste'' refer to?", "options": ["Emails and other electronic messages that a person receives but then chooses to delete without ever reading them", "Discarded electronic devices, which can contain toxic materials and often end up in landfill", "Electrical energy that is wasted when a computer is accidentally left switched on overnight by its owner", "Errors in a program''s code that stop it from running correctly until they are found and fixed by a developer"]}'::jsonb, '{"answer": 1, "explain": "E-waste is discarded electronic equipment, which can contain harmful materials and cause environmental damage if not recycled."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:f22530a0', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Why can something be legal but still raise an ethical concern?", "options": ["Because ethics is about what is right or fair, which is not always the same as what the law happens to allow", "Because anything that is legal is automatically also ethical, so the two ideas can never disagree with each other", "Because ethical concerns only ever apply to technology that has not yet been invented or released to the public", "Because the law changes so often that nothing can really be considered either legal or ethical for very long"]}'::jsonb, '{"answer": 0, "explain": "Legality and ethics are different: a practice can follow the law yet still be seen as unfair or morally questionable."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:04593936', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "A social media company uses AI to decide which posts each user sees. Which pair of impacts does this MOST clearly involve?", "options": ["Only the physical size of the data centre and the total length of the network cables running into it", "Ethical impacts (fairness, influence over users) and privacy impacts (how much user data is collected)", "Only the exact programming language and the specific operating system used to build the AI system itself", "Only the clock speed of the processors and the amount of RAM installed in each of the company''s servers"]}'::jsonb, '{"answer": 1, "explain": "AI choosing what users see raises ethical questions (fairness, influence) and privacy questions (the data used to make those choices)."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:172fa7bf', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Which statement about the impacts of a new technology is the most balanced?", "options": ["Streaming films online is completely good because it is convenient and no discs ever need to be produced", "Streaming films online saves discs and packaging, but the data centres that power it still use a lot of energy", "Streaming films online is completely bad, simply because the data centres that make it all possible use up electrical energy", "Streaming films online has absolutely no positive or negative impact of any kind on anybody, anywhere, at all"]}'::jsonb, '{"answer": 1, "explain": "A balanced view recognises both a benefit (fewer discs/packaging) and a drawback (energy use) — the skill the Discuss question rewards."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:3ab6387e', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "Which of these best describes a stakeholder?", "options": ["The single member of staff who physically assembles a device on the production line inside the factory", "Any person or group who is affected by a technology or by a decision that is made about it", "Only the customer who finally buys the finished technology from a shop or from an online store", "The piece of software that is used to control and monitor the machines in an automated factory"]}'::jsonb, '{"answer": 1, "explain": "A stakeholder is anyone affected by the technology or decision — individuals, businesses, society or the environment."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:6e53f087', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "A company moves from selling software on physical discs to selling it only as downloads. Which is a genuine ENVIRONMENTAL benefit of this?", "options": ["The company can now charge each of its customers a much higher price for exactly the same piece of software", "Fewer discs and less packaging need to be manufactured and shipped, lowering the carbon footprint", "Customers are now completely unable to ever share a copy of the software with any of their friends at all", "The download will always install far more quickly than the software would have done from a physical disc"]}'::jsonb, '{"answer": 1, "explain": "Digital distribution means fewer discs and less packaging are made and shipped, reducing the carbon footprint — an environmental benefit."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:mcq:892bb8e4', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'mcq', 'mcq', 1, '{"question": "In an 8-mark ''Discuss'' question about a company releasing frequent new devices, which point best considers a DIFFERENT stakeholder from the company itself?", "options": ["The company can increase its sales and profits each time it brings out an exciting new model of the device", "Customers face higher costs, and the environment suffers from the extra e-waste that the old devices create", "The company can advertise the new features of the device to build up excitement before it is finally released", "The company might see its reputation improve because it is always seen to have the very newest technology"]}'::jsonb, '{"answer": 1, "explain": "Customers and the environment are stakeholders separate from the company — considering them gives the balance a top-band answer needs."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:05a75b16', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "Something can be legal but still be considered unethical."}'::jsonb, '{"answer": true, "explain": "Correct — ethics is about what is right or fair, which is not always the same as what the law allows."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:16d3a87d', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "The digital divide describes the physical distance between two networked computers."}'::jsonb, '{"answer": false, "explain": "The digital divide is the gap between people who have good access to digital technology and those who do not — not a physical distance."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:441ef308', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "E-waste is a negative environmental impact of digital technology."}'::jsonb, '{"answer": true, "explain": "Correct — discarded electronics can contain toxic materials and add to landfill, a clear negative environmental impact."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:c6d61994', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "Digital technology only ever has negative impacts on the environment."}'::jsonb, '{"answer": false, "explain": "It has positives too, such as less travel from video calls and fewer discs/packaging from digital downloads."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:9d197961', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "A good ''Discuss'' answer only lists the positive impacts of a technology."}'::jsonb, '{"answer": false, "explain": "A top-band ''Discuss'' answer is balanced — it weighs positives AND negatives and reaches a justified conclusion."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:aebc7a90', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "Releasing new devices very frequently tends to increase e-waste."}'::jsonb, '{"answer": true, "explain": "Correct — people replace working devices more often, so more are thrown away, increasing e-waste."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:803999c0', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "Considering more than one stakeholder helps make a discussion of impacts more balanced."}'::jsonb, '{"answer": true, "explain": "Correct — a change can be good for one group and bad for another, so covering several stakeholders gives balance."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tf:984f6a6c', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tf', 'tf', 1, '{"question": "Tracking a user''s browsing to build a profile of them is a privacy impact."}'::jsonb, '{"answer": true, "explain": "Correct — collecting and profiling personal data is a privacy concern about who can see and use that data."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:6f13cbc6', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "What we mean by the ''impacts'' of digital technology", "reading": "<h4>Every technology brings good and bad</h4>\n<ul>\n<li>Digital technology changes the way we live, work and communicate. Almost every change brings <strong>benefits (positive impacts)</strong> AND <strong>problems (negative impacts)</strong> — often at the same time.</li>\n<li>The specification groups these impacts into five areas: <strong>ethical</strong>, <strong>legal</strong>, <strong>cultural</strong>, <strong>environmental</strong> and <strong>privacy</strong>. This page covers the ethical, cultural, environmental and privacy impacts; the <strong>laws</strong> (legal side) are covered in <strong>1.6.1b Legislation</strong>.</li>\n<li>The exam skill is to <strong>weigh up</strong> these impacts — to <strong>discuss</strong> both sides and reach a balanced, justified view, rather than just listing good points or bad points.</li>\n</ul>", "question": "What does it mean to consider the ''impacts'' of a piece of digital technology?", "options": ["Working out only the good things about it so that a business can advertise the product to as many people as possible", "Weighing up both its positive and negative effects on different people, society and the environment", "Measuring exactly how fast the technology runs compared with the older technology that it is replacing", "Deciding whether the technology is legal to sell in the country where it was originally manufactured"]}'::jsonb, '{"answer": 1, "explain": "Considering impacts means weighing the positive AND negative effects on people, society and the environment — not just the benefits."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:65de00e8', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Stakeholders — who is affected?", "reading": "<h4>Different groups feel different impacts</h4>\n<ul>\n<li>A <strong>stakeholder</strong> is any person or group <strong>affected by</strong> a technology or a decision about it.</li>\n<li>Typical stakeholders include: <strong>individuals</strong> (users, customers, employees), <strong>businesses/organisations</strong>, wider <strong>society</strong>, and the <strong>environment</strong>.</li>\n<li>The same change can be <strong>good for one stakeholder and bad for another</strong>. For example, a company releasing a new phone every year <strong>increases its profits</strong> (good for the business) but <strong>adds to e-waste</strong> (bad for the environment) and <strong>costs customers more</strong>.</li>\n<li>Strong exam answers deliberately consider <strong>more than one stakeholder</strong>.</li>\n</ul>", "question": "Why is it useful to think about different stakeholders when discussing a technology''s impact?", "options": ["Because only the company that makes the technology is ever really affected by the decisions that are made about it", "Because the same change can be positive for one group and negative for another, giving a balanced view", "Because stakeholders are the engineers who physically build the technology inside the factory each day", "Because it lets you ignore the environmental effects and focus only on how much money is being made"]}'::jsonb, '{"answer": 1, "explain": "Different stakeholders experience different impacts — a change good for a business can be bad for customers or the environment, which gives a balanced discussion."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:a58d49b8', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Ethical impacts", "reading": "<h4>Is it the right thing to do?</h4>\n<ul>\n<li><strong>Ethical</strong> impacts are about what is <strong>right or wrong, fair or unfair</strong> — the moral side of a decision. Something can be <strong>legal but still unethical</strong>.</li>\n<li>Examples of ethical questions raised by digital technology: Is it fair for <strong>AI to replace people''s jobs</strong>? Is it right for companies to <strong>track users</strong> to sell them things? Is it fair that <strong>only some people can afford</strong> the latest technology? Should devices be designed to <strong>stop working</strong> so people buy new ones?</li>\n<li>There is often <strong>no single correct answer</strong> — the exam wants you to see both sides of the ethical argument.</li>\n</ul>", "question": "What makes an issue an ''ethical'' issue rather than simply a legal one?", "options": ["An ethical issue is only ever about whether a company can make a large enough profit from selling the technology", "An ethical issue is about whether something is right, fair or moral — even if it happens to be perfectly legal", "An ethical issue is always automatically illegal, which is exactly what makes it an ethical problem in the first place", "An ethical issue only affects the environment, whereas a legal issue only ever affects individual people"]}'::jsonb, '{"answer": 1, "explain": "Ethics is about right/wrong and fairness. Something can be legal yet still raise an ethical concern — the two are not the same."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:64f2adbb', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Cultural impacts", "reading": "<h4>How technology changes the way groups of people live</h4>\n<ul>\n<li><strong>Cultural</strong> impacts are the effects on <strong>how groups of people live, work and interact</strong> — on society as a whole.</li>\n<li>Positive examples: people can <strong>stay connected</strong> across the world, work <strong>from home</strong>, access <strong>information and education</strong> online, and form <strong>online communities</strong>.</li>\n<li>Negative examples: <strong>jobs lost</strong> to automation, less <strong>face-to-face</strong> contact, the spread of <strong>misinformation</strong>, pressure from <strong>social media</strong>, and the <strong>digital divide</strong> (covered next).</li>\n</ul>", "question": "Which of these is a cultural impact of digital technology?", "options": ["The exact amount of electrical energy that a large data centre uses to keep all of its servers running each year", "The way social media has changed how people communicate, work and form communities across society", "The specific programming language that a software developer chooses to write a brand new application in", "The number of transistors that engineers are able to fit onto a single modern processor chip nowadays"]}'::jsonb, '{"answer": 1, "explain": "Cultural impacts are about how technology changes the way groups of people live and interact — such as social media changing communication. Energy use is environmental."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:2e31d648', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "The digital divide", "reading": "<h4>Not everyone has the same access</h4>\n<ul>\n<li>The <strong>digital divide</strong> is the <strong>gap between people who have good access</strong> to digital technology and the internet, and those who <strong>do not</strong>.</li>\n<li>Causes include <strong>cost</strong> (not everyone can afford devices or broadband), <strong>location</strong> (some areas have poor or no internet), and <strong>skills/age</strong> (some people lack the confidence or training to use it).</li>\n<li>It matters because so many services — <strong>banking, job applications, school work, government services</strong> — are now online. People on the wrong side of the divide can be <strong>left behind</strong>, which is both a cultural and an ethical concern.</li>\n</ul>", "question": "What is the digital divide?", "options": ["The physical distance between two computers that are trying to communicate with each other over a large network", "The gap between people who have good access to digital technology and the internet and those who do not", "The difference in processing speed between an expensive new computer and a much cheaper older one", "The point at which a hard disk becomes so fragmented that files can no longer be opened by the computer"]}'::jsonb, '{"answer": 1, "explain": "The digital divide is the gap in access to digital technology and the internet, caused by factors such as cost, location and skills."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:65e11384', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Environmental impacts — the problems", "reading": "<h4>Making, powering and throwing away devices</h4>\n<ul>\n<li><strong>Manufacturing</strong> devices uses <strong>raw materials</strong> (including scarce metals) and lots of <strong>energy</strong>, and can cause <strong>pollution</strong>.</li>\n<li><strong>Running</strong> devices, and especially large <strong>data centres</strong>, uses a great deal of <strong>electricity</strong>, much of which still comes from fossil fuels — adding to the <strong>carbon footprint</strong>.</li>\n<li><strong>Disposal</strong> creates <strong>e-waste</strong>: discarded electronics that often contain <strong>toxic materials</strong> and end up in landfill if not recycled.</li>\n</ul>", "question": "Which of these is a negative environmental impact of digital technology?", "options": ["People are able to work from home and hold video meetings instead of driving to a distant office each day", "Discarded electronic devices create e-waste that can contain toxic materials and end up in landfill", "Online shops let customers compare the prices of many different products before deciding what to buy", "Cloud storage means a user can open their files from almost any device with an internet connection"]}'::jsonb, '{"answer": 1, "explain": "E-waste from discarded devices is a negative environmental impact. Working from home is actually a positive environmental impact (less travel)."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:1d23bb57', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Environmental impacts — e-waste and ''throwaway'' culture", "reading": "<h4>Frequent upgrades make the problem worse</h4>\n<ul>\n<li>When companies release <strong>new devices very often</strong> (for example a new phone every year), people replace working devices more frequently, so <strong>more are thrown away</strong> — increasing e-waste.</li>\n<li>This is worsened if devices are hard to repair or are designed to have a <strong>short life</strong> (sometimes called planned obsolescence) — an <strong>ethical</strong> concern as well as an environmental one.</li>\n<li><strong>Ways to reduce the harm:</strong> <strong>recycle</strong> old devices for their components/materials, <strong>donate or redistribute</strong> working devices to people who need them, design products to be <strong>repairable</strong>, and choose <strong>digital downloads</strong> over physical discs (fewer materials, smaller carbon footprint from distribution).</li>\n</ul>", "question": "How does releasing a new version of a device every year tend to affect the environment?", "options": ["It has no environmental effect at all, because the old devices simply disappear on their own over time", "It increases e-waste, because people replace working devices more often, so more are thrown away", "It reduces e-waste, because manufacturers always collect and fully recycle every single old device by law", "It only affects the environment if the new device is physically larger than the one it is replacing"]}'::jsonb, '{"answer": 1, "explain": "Frequent new releases lead people to replace working devices more often, so more are discarded — increasing e-waste."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:926b9864', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Environmental impacts — the positives", "reading": "<h4>Technology can also help the planet</h4>\n<ul>\n<li>Not all environmental impacts are negative. Digital technology also <strong>reduces</strong> some environmental harm:</li>\n<li><strong>Less travel:</strong> video calls and remote working mean fewer journeys, lowering emissions.</li>\n<li><strong>Less paper:</strong> digital documents, email and online forms reduce paper use and printing.</li>\n<li><strong>Digital distribution:</strong> downloading software, music and films means <strong>fewer discs manufactured</strong>, less packaging, and a <strong>smaller carbon footprint</strong> than shipping physical copies.</li>\n<li>A good discussion mentions <strong>both</strong> the harm and these benefits.</li>\n</ul>", "question": "Which of these is a positive environmental impact of digital technology?", "options": ["The very large amount of electricity that data centres need in order to keep their many servers running all day long", "Distributing software as downloads instead of on discs, which means fewer discs and less packaging are made", "The toxic materials that can leak out of discarded electronic devices when they are left in landfill sites", "The scarce metals and raw materials that have to be mined in order to manufacture brand new devices"]}'::jsonb, '{"answer": 1, "explain": "Digital downloads mean fewer discs and less packaging are manufactured, a positive environmental impact. The other options are all negative impacts."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:4b0fa91d', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "Privacy impacts", "reading": "<h4>Technology knows a lot about us</h4>\n<ul>\n<li>Digital technology <strong>collects and stores personal data</strong> — what we search, buy, watch and where we go (location).</li>\n<li>This brings <strong>convenience</strong> (personalised recommendations, targeted services), but raises <strong>privacy</strong> concerns: who can see this data, how securely is it stored, and could it be used to <strong>track or profile</strong> us without our knowledge?</li>\n<li>Concerns include <strong>surveillance</strong>, data being <strong>shared or sold</strong>, and large <strong>data breaches</strong>. This is why the law (the <strong>Data Protection Act</strong>, covered in 1.6.1b) exists to control how personal data is handled.</li>\n</ul>", "question": "Why does collecting large amounts of personal data raise privacy concerns?", "options": ["Because personal data always makes a computer run much more slowly than it otherwise would have done", "Because the data could be used to track or profile people, or be shared, sold or exposed in a breach", "Because collecting personal data is the only way that a website is ever able to load its pages correctly", "Because personal data takes up so much storage space that there is no room left for anything else at all"]}'::jsonb, '{"answer": 1, "explain": "Stored personal data can be used to track or profile people, and could be shared, sold or exposed in a breach — the core privacy concern."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:learn:5599d13e', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'learn', 'mcq', 1, '{"readingTitle": "The ''Discuss'' 8-mark question", "reading": "<h4>The most important skill on this topic</h4>\n<ul>\n<li>This topic is the home of the <strong>8-mark \"Discuss\"</strong> question. It always gives a scenario and usually a bullet list of things to <strong>include</strong>.</li>\n<li>It is <strong>levelled (banded)</strong>, so marks reward a <strong>balanced, developed argument</strong>, not a list. To reach the top band you should:</li>\n<li><strong>1.</strong> Cover <strong>positive AND negative</strong> impacts.</li>\n<li><strong>2.</strong> Consider <strong>more than one stakeholder</strong> (e.g. the company AND its customers AND the environment).</li>\n<li><strong>3.</strong> <strong>Apply</strong> each point to the specific scenario, following it through to a consequence.</li>\n<li><strong>4.</strong> Reach a <strong>justified conclusion</strong> — an overall view with a reason.</li>\n</ul>", "question": "What most separates a top-band answer on an 8-mark ''Discuss the impact'' question from a weaker one?", "options": ["Writing down as many separate points as you possibly can, all on the positive side, without spending any time on the drawbacks", "Giving a balanced argument with positives and negatives, more than one stakeholder, and a justified conclusion", "Using the longest and most complicated technical words that the student can possibly think of throughout", "Writing the entire answer as a single long bullet-point list with no full sentences used anywhere in it"]}'::jsonb, '{"answer": 1, "explain": "Top-band ''Discuss'' answers are balanced (both sides), consider more than one stakeholder, apply to the scenario, and reach a justified conclusion."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:misc:c1d25a1c', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a ''Discuss'' answer should just list as many good points (or as many bad points) as possible.</p><p><strong>✅ The correct idea:</strong> A <strong>Discuss</strong> question is <strong>levelled</strong> and rewards a <strong>balanced argument</strong>: cover <strong>positive AND negative</strong> impacts, consider <strong>more than one stakeholder</strong>, apply each point to the <strong>scenario</strong>, and finish with a <strong>justified conclusion</strong>. A one-sided list stays in the lower bands.</p>", "question": "What should a top-band answer to a ''Discuss the impacts'' question always include?", "options": ["A long one-sided list of only the advantages, because that is what shows the examiner the most knowledge", "Both positive and negative impacts, more than one stakeholder, and a justified overall conclusion", "The full technical specification of every device that is mentioned anywhere in the question scenario", "A promise that the technology will definitely never cause any problems for anybody at any time in the future"]}'::jsonb, '{"answer": 1, "explain": "Balance is the key: both sides, more than one stakeholder, applied to the scenario, with a justified conclusion."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:misc:150bbc43', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing that if something is legal, there is nothing left to discuss ethically.</p><p><strong>✅ The correct idea:</strong> Legal and ethical are <strong>different</strong>. A company can act <strong>within the law</strong> and still do something many people think is <strong>unfair or wrong</strong> — for example designing devices to fail sooner, or tracking users to sell their data. Ethics asks ''is it <strong>right</strong>?'', not just ''is it <strong>allowed</strong>?''.</p>", "question": "A company tracks its users within the law but many people feel it is unfair. What does this show?", "options": ["That there can be no problem at all, because the company has not actually broken any law by doing this", "That something can be legal yet still raise an ethical concern about whether it is fair or right", "That the company must have broken the law, because tracking users is always completely illegal everywhere", "That ethics and the law are exactly the same thing, so if it is legal it must automatically also be ethical"]}'::jsonb, '{"answer": 1, "explain": "Acting within the law does not settle the ethics — a legal practice can still be seen as unfair, which is an ethical concern."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:misc:6b6deea1', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming digital technology is only ever bad for the environment.</p><p><strong>✅ The correct idea:</strong> There are real <strong>negatives</strong> (manufacturing, energy use, e-waste) but also real <strong>positives</strong>: <strong>less travel</strong> (video calls), <strong>less paper</strong>, and <strong>digital distribution</strong> meaning fewer discs and less packaging. A balanced answer gives <strong>both</strong> sides.</p>", "question": "Which is a genuine positive environmental impact of digital technology?", "options": ["The rare metals and all of the other raw materials that must be mined out from deep underground in order to build brand new devices", "Working and holding meetings from home over video calls, which reduces the need to travel and cuts emissions", "The dangerous toxic substances that can escape from electronic devices left to rot in a landfill site", "The large amount of electricity that busy data centres consume in order to stay running around the clock"]}'::jsonb, '{"answer": 1, "explain": "Remote working via video calls reduces travel and emissions — a genuine positive. The others are all negative environmental impacts."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:misc:a5454670', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing cultural impacts with environmental impacts.</p><p><strong>✅ The correct idea:</strong> <strong>Cultural</strong> impacts are about <strong>people and society</strong> — how we live, work, communicate and who has access (the digital divide). <strong>Environmental</strong> impacts are about the <strong>planet</strong> — energy, raw materials and e-waste. Ask: is this point about <strong>people</strong> or about the <strong>environment</strong>?</p>", "question": "Which of these is a cultural impact rather than an environmental one?", "options": ["The amount of electricity used by the millions of servers running inside the world''s largest data centres", "The way that social media has changed how people communicate and form communities across society", "The e-waste created when people throw away their old and unwanted electronic devices such as phones", "The scarce raw materials that must be mined out of the ground in order to manufacture new devices"]}'::jsonb, '{"answer": 1, "explain": "Social media changing how people communicate is a cultural (people/society) impact; the others are all environmental (planet) impacts."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:misc:06ec1e98', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking the digital divide is only about who owns the newest, most expensive gadgets.</p><p><strong>✅ The correct idea:</strong> The digital divide is about <strong>access</strong> to digital technology and the internet, driven by <strong>cost, location and skills</strong>. It matters because essential services — <strong>banking, jobs, education, government</strong> — are online, so people without access are genuinely <strong>left behind</strong>, not just missing out on gadgets.</p>", "question": "Why does the digital divide matter so much today?", "options": ["Because people without the latest gadgets are unable to play the newest and most demanding video games", "Because so many essential services are now online, so people without access can be left behind", "Because the newest devices are always noticeably faster than the older ones that some people still use", "Because it decides which country will manufacture the largest number of new devices in the coming year"]}'::jsonb, '{"answer": 1, "explain": "Essential services (banking, jobs, education, government) are online, so lacking access has serious real-world consequences — not just missing new gadgets."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tips:80a737c4', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — How to structure the 8-mark ''Discuss'' answer", "reading": "<p>Almost every 8-marker on this topic is a <strong>Discuss</strong> question with a scenario and a bullet list of things to <strong>include</strong>. Use the bullets as your plan and follow this structure:</p>\n<ul>\n<li><strong>Both sides:</strong> give <strong>positive</strong> impacts and <strong>negative</strong> impacts — never one-sided.</li>\n<li><strong>More than one stakeholder:</strong> e.g. the company, its customers, wider society, the environment. This is the fastest way to add balance.</li>\n<li><strong>Apply + develop:</strong> take each point back to the specific scenario and follow it through to a consequence (point → because → so…).</li>\n<li><strong>Justified conclusion:</strong> end with an overall view and a reason (\"On balance… because…\").</li>\n</ul>\n<p><strong>Band 3 (6–8):</strong> balanced, developed, applied to the scenario, justified conclusion. <strong>Band 2 (3–5):</strong> some points but one-sided or generic. <strong>Band 1 (1–2):</strong> a few simple, unexplained statements.</p>", "question": "A student''s 8-mark ''Discuss'' answer only gives negative impacts, all about the company. What two things would most improve it?", "options": ["Making the sentences much longer, and repeating each of the negative points a second time in different words", "Adding some positive impacts as well, and considering other stakeholders such as customers or the environment", "Removing the conclusion entirely, and listing the negative points as single words rather than in full sentences", "Adding the full technical specification of the company''s product and the date it was first released to the public"]}'::jsonb, '{"answer": 1, "explain": "Balance is what lifts the band: add positives as well as negatives, and bring in other stakeholders beyond the company."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tips:fbd9a98b', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tips', 'mcq', 1, '{"readingTitle": "tip — Sort every point: ethical, cultural, environmental or privacy?", "reading": "<p>Questions sometimes ask specifically for, say, the <strong>environmental</strong> impacts. Don''t drift into the wrong area. A quick test for each point:</p>\n<ul>\n<li><strong>Ethical</strong> — is it about right/wrong or fairness? (\"Is it fair to…\")</li>\n<li><strong>Cultural</strong> — is it about how people live, work or communicate? (jobs, the digital divide, social media)</li>\n<li><strong>Environmental</strong> — is it about the planet? (energy, raw materials, e-waste)</li>\n<li><strong>Privacy</strong> — is it about personal data being collected, tracked or shared?</li>\n</ul>\n<p>If a question says \"environmental\", write about energy, materials and e-waste — not about jobs or fairness, which are cultural and ethical.</p>", "question": "A question asks only for the ENVIRONMENTAL impacts of a decision. Which point should you include?", "options": ["The fact that some workers might lose their jobs if the company decides to automate part of its factory", "The increase in e-waste and the energy used to manufacture and run the new devices being produced", "The worry that the company could unfairly track its customers in order to sell them even more products", "The way that the new technology might change how people in a community communicate with one another"]}'::jsonb, '{"answer": 1, "explain": "Environmental impacts are about the planet — e-waste and energy use. Jobs are cultural, tracking is privacy, fairness is ethical."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:tips:f917f1ff', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'tips', 'mcq', 1, '{"readingTitle": "tip — Learn the stakeholder trick for instant balance", "reading": "<p>The quickest way to make a discussion balanced is to run through the <strong>stakeholders</strong> and ask how the decision affects each one:</p>\n<ul>\n<li><strong>The company/organisation</strong> — profit, sales, reputation, costs.</li>\n<li><strong>Customers/individuals</strong> — cost, convenience, choice, privacy.</li>\n<li><strong>Society</strong> — jobs, the digital divide, how people live.</li>\n<li><strong>The environment</strong> — energy, materials, e-waste.</li>\n</ul>\n<p>Even naming <strong>two or three</strong> of these and giving one impact for each turns a one-sided answer into a balanced one — exactly what the top band needs.</p>", "question": "How does thinking about stakeholders quickly make a discussion more balanced?", "options": ["It lets you focus entirely on the company, which is the only stakeholder that the examiner is interested in", "A decision often helps one stakeholder while harming another, so covering several naturally gives both sides", "It means you never have to mention any negative impacts, because stakeholders only ever gain from technology", "It replaces the need for a conclusion, since simply naming the stakeholders is enough to reach the top band"]}'::jsonb, '{"answer": 1, "explain": "Different stakeholders gain or lose differently, so running through them naturally surfaces both positive and negative impacts."}'::jsonb),
('computer-science:1-6-1a-impacts-of-digital-technology:fib:052a3261', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'fib', 'fib', 1, '{"question": "A _____ is any person or group affected by a technology or a decision made about it.", "blankOptions": {"B1": ["e-waste", "stakeholder", "privacy", "positive"]}}'::jsonb, '{"blanks": {"B1": "stakeholder"}}'::jsonb),
