('computer-science:1-6-1a-impacts-of-digital-technology:match:dab5956c', 'computer-science', 'computer-science:1-6-1a-impacts-of-digital-technology', '1.6.1a Ethical, Cultural & Environmental Impacts', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Impact (of technology)”?", "options": ["An extended answer weighing positives and negatives to reach a justified view", "A positive or negative effect a technology has on people, society or the environment", "Effects on how groups of people live, work and interact", "Concerns about what is right, fair or moral — even if it is legal"]}'::jsonb, '{"answer": 1, "explain": "“Impact (of technology)” means: A positive or negative effect a technology has on people, society or the environment"}'::jsonb),
