('computer-science:1-6-1b-legislation:exam:138e7bad', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'exam', 'mcq', 1, '{"num": "Q1", "question": "<p>Tick <strong>one</strong> box to identify the law that makes it illegal to access a computer system without permission.</p>", "options": ["Data Protection Act 2018", "Computer Misuse Act 1990", "Copyright, Designs and Patents Act 1988", "Freedom of Information Act 2000"], "hint": "Which law is about hacking / accessing systems without permission?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Computer Misuse Act 1990</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Computer Misuse Act 1990."}'::jsonb),
('computer-science:1-6-1b-legislation:exam:d2066e9f', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'exam', 'mcq', 1, '{"num": "Q2", "question": "<p>Tick <strong>one</strong> box to identify the law that protects original work such as software, music and images from being copied.</p>", "options": ["Data Protection Act 2018", "Copyright, Designs and Patents Act 1988", "Computer Misuse Act 1990", "Freedom of Information Act 2000"], "hint": "Which law is about copying someone''s original work without permission?"}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Copyright, Designs and Patents Act 1988</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "Copyright, Designs and Patents Act 1988."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:f30437aa', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which law makes it illegal to access a computer system without permission?", "options": ["The Data Protection Act 2018", "The Computer Misuse Act 1990", "The Copyright, Designs and Patents Act 1988", "The Freedom of Information Act 2000"]}'::jsonb, '{"answer": 1, "explain": "The Computer Misuse Act 1990 makes unauthorised access to computer systems (hacking) illegal."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:b3f29fca', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which law would a school be following when it keeps its students'' personal records secure and private?", "options": ["The Copyright, Designs and Patents Act, because the school created the records and therefore owns them fully", "The Data Protection Act 2018", "The Computer Misuse Act, because the records are stored on one of the school''s own computer systems", "The Freedom of Information Act, because parents are allowed to request to see their own child''s school records"]}'::jsonb, '{"answer": 1, "explain": "Keeping personal data (student records) secure and private is required by the Data Protection Act 2018."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:9fabb96b', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "A person downloads and shares a paid-for game for free without the creator''s permission. Which law does this break?", "options": ["The Data Protection Act 2018, because the game will contain some personal data about the people who made it", "The Copyright, Designs and Patents Act 1988", "The Computer Misuse Act 1990", "The Freedom of Information Act 2000"]}'::jsonb, '{"answer": 1, "explain": "Copying and sharing someone''s software without permission (software piracy) breaches the Copyright, Designs and Patents Act 1988."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:56abb0d6', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which of these is one of the offences covered by the Computer Misuse Act 1990?", "options": ["Keeping personal data for a little longer than the organisation that collected it actually needed to keep it", "Making an unauthorised modification to data, for example by deleting files or spreading a virus", "Selling a piece of software that you wrote entirely yourself to as many customers as you possibly can", "Requesting information from a local council about how it has chosen to spend its money over the last year"]}'::jsonb, '{"answer": 1, "explain": "Unauthorised modification of data (e.g. deleting files or spreading malware) is one of the Computer Misuse Act''s offences."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:7e7f381a', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "A member of the public asks their local council how much it spent on new computers last year. Which law gives them the right to ask?", "options": ["The Data Protection Act 2018", "The Freedom of Information Act 2000", "The Computer Misuse Act 1990", "The Copyright, Designs and Patents Act 1988"]}'::jsonb, '{"answer": 1, "explain": "The Freedom of Information Act 2000 lets the public request information held by public authorities such as a council."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:25549f65', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which of these is a responsibility placed on an organisation by the Data Protection Act 2018?", "options": ["It must give a free copy of any software it has created to anybody who politely asks the company for one", "It must keep personal data secure and must not share or sell it without the person''s consent", "It must allow anyone at all to access its computer systems so long as they do not change any of the data", "It must release a brand new version of its product every single year to keep its customers fully up to date"]}'::jsonb, '{"answer": 1, "explain": "The DPA requires personal data to be kept secure and not shared or sold without consent."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:cf376408', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "A designer copies another company''s logo and uses it on their own product without asking. Which law does this break?", "options": ["The Computer Misuse Act 1990, because copying the logo means gaining access to the other company''s systems", "The Copyright, Designs and Patents Act 1988", "The Data Protection Act 2018", "The Freedom of Information Act 2000"]}'::jsonb, '{"answer": 1, "explain": "A logo is an original work protected by copyright, so copying it without permission breaches the Copyright, Designs and Patents Act 1988."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:2ebc3d29', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "An employee logs into their manager''s account without permission to read confidential emails. Which law is broken?", "options": ["The Copyright, Designs and Patents Act 1988", "The Computer Misuse Act 1990", "The Freedom of Information Act 2000", "The Data Protection Act 2018"]}'::jsonb, '{"answer": 1, "explain": "Accessing an account without permission is unauthorised access — an offence under the Computer Misuse Act 1990."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:4d6f2c56', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Why is storing customer data covered by the Data Protection Act rather than the Computer Misuse Act?", "options": ["Because the Computer Misuse Act only ever applies to computers that are connected to the public internet", "Because the Data Protection Act is the law that specifically governs how personal data is stored and used", "Because the Computer Misuse Act only applies to schools and colleges, never to ordinary private businesses", "Because storing any data at all is always automatically a form of misusing a computer under the older law"]}'::jsonb, '{"answer": 1, "explain": "The Data Protection Act specifically governs personal data; the Computer Misuse Act is about unauthorised access, not routine data storage."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:b0a7a769', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "The Copyright, Designs and Patents Act 1988 protects which of the following?", "options": ["The personal contact details and payment information of every customer stored in a company''s database", "Original work such as software, music, images and writing created by a person or company", "Computer networks and systems from being broken into by someone who does not have permission to use them", "The right of members of the public to see information that is held about them by government departments"]}'::jsonb, '{"answer": 1, "explain": "The CDPA protects original work (intellectual property) such as software, music, images and writing."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:8fdd6384', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which pairing of a situation with the correct law is right?", "options": ["Spreading a virus that deletes a company''s files → the Freedom of Information Act, because files are information", "Spreading a virus that deletes a company''s files → the Computer Misuse Act 1990", "Losing a laptop full of unencrypted customer data → the Copyright, Designs and Patents Act 1988", "Copying a song and selling it without permission → the Data Protection Act, because a song is personal to its writer"]}'::jsonb, '{"answer": 1, "explain": "Spreading a virus to delete files is unauthorised modification — a Computer Misuse Act offence. The other pairings are matched to the wrong law."}'::jsonb),
('computer-science:1-6-1b-legislation:mcq:75ff2000', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'mcq', 'mcq', 1, '{"question": "Which of these best describes the difference between the Data Protection Act and the Freedom of Information Act?", "options": ["They are really just one and the same single law, only written down with two completely different names by two separate parts of the government", "Data Protection protects individuals'' personal data; Freedom of Information lets the public access public bodies'' information", "Data Protection applies only to schools, while Freedom of Information applies only to large private companies", "Data Protection is about copying software, while Freedom of Information is about hacking into computer systems"]}'::jsonb, '{"answer": 1, "explain": "The DPA protects personal data about individuals; the FoI Act opens up information held by public authorities — opposite purposes."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:fdab4cb3', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "The Computer Misuse Act 1990 makes hacking into a computer system illegal."}'::jsonb, '{"answer": true, "explain": "Correct — the Computer Misuse Act makes unauthorised access to computer systems (hacking) a criminal offence."}'::jsonb)
